/* Requerimientos de la prevision de demanda.

   Se crea una consulta que relacione todas las columnas pertinentes por medio de joins, agregaciones y
   la creacion de nuevas columnas que faciliten el analisis. Esta consulta se utilizara en otro store
   procedure que en una nueva carpeta 'gold' guardara los archivos particionados por año y mes. Se
   ejecuta com sigue:
*/

USE nyc_taxi_ldw;

EXEC gold.sp_gold_trip_data_green '2020', '01';
EXEC gold.sp_gold_trip_data_green '2020', '02';
EXEC gold.sp_gold_trip_data_green '2020', '03';
EXEC gold.sp_gold_trip_data_green '2020', '04';
EXEC gold.sp_gold_trip_data_green '2020', '05';
EXEC gold.sp_gold_trip_data_green '2020', '06';
EXEC gold.sp_gold_trip_data_green '2020', '07';
EXEC gold.sp_gold_trip_data_green '2020', '08';
EXEC gold.sp_gold_trip_data_green '2020', '09';
EXEC gold.sp_gold_trip_data_green '2020', '10';
EXEC gold.sp_gold_trip_data_green '2020', '11';
EXEC gold.sp_gold_trip_data_green '2020', '12';
EXEC gold.sp_gold_trip_data_green '2021', '01';
EXEC gold.sp_gold_trip_data_green '2021', '02';
EXEC gold.sp_gold_trip_data_green '2021', '03';
EXEC gold.sp_gold_trip_data_green '2021', '04';
EXEC gold.sp_gold_trip_data_green '2021', '05';
EXEC gold.sp_gold_trip_data_green '2021', '06';
EXEC gold.sp_gold_trip_data_green '2021', '07';


/* Una vez guardadas en gold con particiones, se crea una view con columnas especificando las 
    particiones a las que corresponde y asi lograr un filtro mas eficiente cuando se llame la tabla. 
*/

USE nyc_taxi_ldw
GO

DROP VIEW IF EXISTS gold.vw_trip_data_green 
GO

CREATE VIEW gold.vw_trip_data_green 
AS
    SELECT
        trip_data_green.filepath(1) AS year,
        trip_data_green.filepath(2) AS month,
        trip_data_green.*
    FROM
        OPENROWSET(
            BULK 'gold/trip_data_green/year=*/month=*/*.parquet',
            DATA_SOURCE = 'nyc_taxi_src',
            FORMAT = 'PARQUET'
    )
    WITH (
        Borough VARCHAR(15),
        trip_date DATE,
        trip_day VARCHAR(10),
        trip_day_weekend_ind CHAR(1),
        card_trip_count INT,
        cash_trip_count INT,
        street_hail_trip_count INT,
        dispatch_trip_count INT,
        trip_distance FLOAT,
        trip_duration INT,
        fare_amount FLOAT
    ) AS trip_data_green
GO

USE nyc_taxi_ldw

CREATE EXTERNAL DATA SOURCE nyc_taxi_src
WITH
  (  LOCATION = 'https://synapseadls1.dfs.core.windows.net/nyc-taxi-data'
  );
